class Solution {
public:
    long long findMaximumNumber(long long k, int x) {
        long long low = 1, high = 1LL << 60;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            if (accumulatedPrice(mid, x) <= k) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return high;
    }

private:
    long long accumulatedPrice(long long num, int x) {
        long long total = 0;
        for (int p = x; p <= 60; ++p) {
            long long bitPos = 1LL << p;
            long long fullCycles = (num + 1) / (bitPos << 1);
            long long remainder = (num + 1) % (bitPos << 1);
            total += fullCycles * (1LL << (p - 1));
            total += max(0LL, remainder - bitPos);
        }
        return total;
    }
};
